-- =========== tb_inquiry ===========
CREATE TABLE tb_inquiry (
  inquiry_id BIGINT NOT NULL GENERATED ALWAYS AS IDENTITY,
  user_id varchar(50) NOT NULL,
  user_name varchar(50) NOT NULL,
  title varchar(300) NOT NULL,
  body TEXT NOT NULL,
  inquiry_date TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  predicted_category varchar(30),
  predicted_confidence decimal(5,4),
  classified_by_model varchar(50),
  classified_at TIMESTAMP,
  actual_category varchar(30),
  assigned_to varchar(50),
  reroute_count INTEGER NOT NULL DEFAULT 0,
  answer_body TEXT,
  answered_by varchar(50),
  answered_at TIMESTAMP,
  resolution_state varchar(20) NOT NULL DEFAULT 'OPEN',
  user_satisfaction SMALLINT,
  reg_dt TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  upd_dt TIMESTAMP /*PG_TODO_ON_UPDATE*/,
  is_deleted char(1) NOT NULL DEFAULT 'N',
  PRIMARY KEY (inquiry_id)
);

CREATE INDEX ix_tb_inquiry_user ON tb_inquiry (user_id, inquiry_date);
CREATE INDEX ix_tb_inquiry_state ON tb_inquiry (resolution_state, inquiry_date);
CREATE INDEX ix_tb_inquiry_predicted ON tb_inquiry (predicted_category, classified_at);
CREATE INDEX ix_tb_inquiry_actual ON tb_inquiry (actual_category, reg_dt);
CREATE INDEX ix_tb_inquiry_assigned ON tb_inquiry (assigned_to, resolution_state);
CREATE INDEX ix_tb_inquiry_inquiry_date ON tb_inquiry (inquiry_date);
COMMENT ON COLUMN tb_inquiry.predicted_category IS 'ACADEMIC|ORDER|SYSTEM|OTHER';
COMMENT ON COLUMN tb_inquiry.predicted_confidence IS '0.0000 ~ 1.0000';
COMMENT ON COLUMN tb_inquiry.classified_by_model IS 'qwen2.5:7b@v3 식 모델 버전';
COMMENT ON COLUMN tb_inquiry.actual_category IS '운영자 확정 카테고리';
COMMENT ON COLUMN tb_inquiry.assigned_to IS '담당자 user_id';
COMMENT ON COLUMN tb_inquiry.resolution_state IS 'OPEN|ANSWERED|RESOLVED|CLOSED';
COMMENT ON COLUMN tb_inquiry.user_satisfaction IS '1-5 별점';

