-- ============================================
-- ON UPDATE CURRENT_TIMESTAMP 트리거
-- ============================================
-- 공용 트리거 함수 (한 번만 정의 — 첫 번째 V 에서만 CREATE)
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'set_upd_dt_now') THEN
        EXECUTE $func$
            CREATE FUNCTION set_upd_dt_now() RETURNS trigger AS $body$
            BEGIN
                IF TG_OP = 'UPDATE' THEN
                    -- 컬럼명이 upd_dt 또는 updated_at 인 경우 모두 처리
                    BEGIN
                        NEW.upd_dt := CURRENT_TIMESTAMP;
                    EXCEPTION WHEN OTHERS THEN
                        BEGIN
                            NEW.updated_at := CURRENT_TIMESTAMP;
                        EXCEPTION WHEN OTHERS THEN
                            NULL;
                        END;
                    END;
                END IF;
                RETURN NEW;
            END;
            $body$ LANGUAGE plpgsql;
        $func$;
    END IF;
END $$;


DROP TRIGGER IF EXISTS trg_tb_inquiry_upd_dt ON tb_inquiry;
CREATE TRIGGER trg_tb_inquiry_upd_dt BEFORE UPDATE ON tb_inquiry
  FOR EACH ROW EXECUTE FUNCTION set_upd_dt_now();

DROP TRIGGER IF EXISTS trg_tb_inquiry_train_upd_dt ON tb_inquiry_train;
CREATE TRIGGER trg_tb_inquiry_train_upd_dt BEFORE UPDATE ON tb_inquiry_train
  FOR EACH ROW EXECUTE FUNCTION set_upd_dt_now();

DROP TRIGGER IF EXISTS trg_tb_inquiry_stats_monthly_upd_dt ON tb_inquiry_stats_monthly;
CREATE TRIGGER trg_tb_inquiry_stats_monthly_upd_dt BEFORE UPDATE ON tb_inquiry_stats_monthly
  FOR EACH ROW EXECUTE FUNCTION set_upd_dt_now();
